(function(){
  const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
  const esc=s=>String(s||'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
  const ROUTES=[
    {id:'care',title:'GoalOS Care Command',href:'goalos-care-command.html',keywords:['care','take care','what i want','goalos do it','front door','chatgpt','box','command'],why:'Use the front-and-center command interface: plain-language objective, clear proof path, Ask GoalOS chat, and route handoff.'},
    {id:'takecare',title:'GoalOS Take-Care Console',href:'goalos-take-care.html',keywords:['take care','simple','mission package'],why:'Use the simpler mission-package console if you want one box and a receipt.'},
    {id:'ask',title:'Ask GoalOS',href:'ask-goalos.html',keywords:['ask','question','where','find','help','route'],why:'Ask a public-site question and get a local answer plus route.'},
    {id:'evidence',title:'Evidence Docket Composer',href:'evidence-docket-composer.html',keywords:['proof','evidence','docket','claim','source','verify','audit','review','provenance'],why:'Build the proof room before the claim: manifest, claims matrix, provenance, proof packets, verifier report, risk ledger, replay path, and Chronicle.'},
    {id:'until',title:'Until-DONE Mission Control',href:'until-done-mission-control.html',keywords:['done','until','state','mission control','objective','gate','complete'],why:'Run the objective through proof gates until the mission is review-ready.'},
    {id:'settlement',title:'Proof-Settlement Lifecycle',href:'proof-settlement-lifecycle.html',keywords:['settle','settlement','escrow','job','proofbundle','chronicle','payment','funds','validate'],why:'Follow Request → Execute → Proof → Validate → Settle → Chronicle in a public-safe simulation.'},
    {id:'rsi',title:'Loop → RSI Control Room',href:'loop-to-rsi-control-room.html',keywords:['loop','rsi','recursive','restart','trace','eci','baseline','move','dossier','target','emit','filter','atlas','eval'],why:'Convert a restartable loop into deterministic RSI governance with ECI, baselines, replay, stress testing, dossier, and Chronicle.'},
    {id:'asi',title:'Superintelligence Proof Governance Console',href:'superintelligence-proof-governance-console.html',keywords:['asi','superintelligence','horizon','council','authority','capacity','governance','firewall'],why:'Inspect the high-assurance governance horizon without claiming achieved ASI: evidence, replay, baselines, council review, and human boundary.'},
    {id:'legal',title:'Legal / Data-Zero Boundary',href:'legal.html',keywords:['legal','privacy','gdpr','regulation','tax','investment','token','wallet','audit','responsibility','boundary','data'],why:'Confirm the public-safe boundary: no user data wanted, no wallet, no token approval, no advice, no external audit claim, and no production authority.'},
    {id:'all',title:'Complete Route Index',href:'complete-route-index.html',keywords:['all','pages','missing','route','catalog','index','command center','find'],why:'Open the full route constellation so no preserved page disappears.'},
    {id:'institution',title:'Canonical Proof Institution',href:'canonical-proof-institution.html',keywords:['institution','canonical','proof institution','overview','doctrine'],why:'See the complete institutional map: doctrine, route integrity, proof boundary, and next best paths.'},
    {id:'concierge',title:'Experience Concierge',href:'experience-concierge.html',keywords:['new','start','begin','guide','concierge','explain','overview'],why:'Use a guided path if this is your first visit.'}
  ];
  const steps=['Interpret objective','Draft Mission Contract','Compose Evidence Docket plan','Select Verifier Mesh','Emit Governed Decision State','Recommend route handoff','Prepare local receipt'];
  const docket=['Manifest','Claims matrix','Source/provenance plan','Proof packets','Verifier report','Risk ledger','Replay path','Chronicle entry'];
  const verifier=['Claim support','Contradiction check','Public/private boundary','Risk class','Replay readiness','Human review boundary'];
  let last=null;
  function score(text,route){const t=String(text||'').toLowerCase();let s=0;for(const k of route.keywords){if(t.includes(k))s+=k.length>6?4:2}if(route.id==='care')s+=1;if(!t.trim()&&route.id==='care')s+=10;return s}
  function choose(text){let ranked=ROUTES.map(r=>({...r,score:score(text,r)})).sort((a,b)=>b.score-a.score);let top=ranked[0];if(top.score<=1&&text.trim().length>10)top=ROUTES[0];return {top,alts:ranked.filter(r=>r.href!==top.href).slice(0,4),confidence:Math.min(98,Math.max(64,56+top.score*6))}}
  function contract(text,top){const clean=String(text||'').trim()||'Begin with GoalOS and choose the right proof path.';return {objective:clean,decisionToSupport: top.id==='legal'?'Which public-safe boundary applies?':top.id==='settlement'?'Is this work settlement-ready?':top.id==='rsi'?'Can this loop advance into RSI governance?':'What proof path should the user open next?',doneCondition:'A human-review-ready proof path exists with route handoff, claim boundary, and local receipt.',reviewRequirement:'Human review remains required before factual, legal, financial, security, audit, Mainnet, or production authority claims.'}}
  function build(text){const selected=choose(text);const c=contract(text,selected.top);const receipt={receiptType:'GoalOSCareCommandReceipt',version:'v66-goalos-care-command',generatedAt:new Date().toISOString(),objective:c.objective,recommendedRoute:{title:selected.top.title,href:selected.top.href,why:selected.top.why,confidence:selected.confidence},alternatives:selected.alts.map(a=>({title:a.title,href:a.href,why:a.why})),missionContract:c,evidenceDocketPlan:docket,verifierMesh:verifier,governedDecisionState:{verdict:'READY_FOR_PUBLIC_SAFE_ROUTE_HANDOFF',mode:selected.top.id,authority:'local guidance only'},publicSafeBoundary:{noAccount:true,noFormSubmission:true,noWallet:true,noTokenApproval:true,noNetworkRequestFromConsole:true,noAnalytics:true,noCookies:true,noBrowserStorage:true,noTransactionBroadcast:true,noProductionAuthority:true,noUserDataRetained:true}};last=receipt;return receipt}
  function render(r){$('[data-care-route-title]').textContent=r.recommendedRoute.title;$('[data-care-route-why]').textContent=r.recommendedRoute.why;$('[data-care-confidence]').textContent=r.recommendedRoute.confidence+'%';$('[data-care-mode]').textContent=r.governedDecisionState.mode;$('[data-care-risk]').textContent='public-safe';const open=$('[data-care-open]');open.href=r.recommendedRoute.href;open.textContent='Open '+r.recommendedRoute.title+' →';$('[data-care-status]').innerHTML=[['0','wallet calls'],['0','user data retained'],[String(r.evidenceDocketPlan.length),'docket elements'],[String(r.verifierMesh.length),'verifier checks']].map(x=>'<div><b>'+esc(x[0])+'</b><span>'+esc(x[1])+'</span></div>').join('');$('[data-care-guidance]').innerHTML='<h3>What GoalOS prepared</h3><ol>'+steps.map(s=>'<li>'+esc(s)+'</li>').join('')+'</ol>';$('[data-care-alternatives]').innerHTML='<p class="care-kicker" style="width:100%;margin-top:8px">Alternative routes</p>'+r.alternatives.map(a=>'<a class="care-btn" href="'+esc(a.href)+'">'+esc(a.title)+'</a>').join('');$('[data-care-contract]').textContent=r.missionContract.decisionToSupport;$('[data-care-contract-copy]').textContent=r.missionContract.doneCondition;$('[data-care-docket]').innerHTML=r.evidenceDocketPlan.map(x=>'<li>'+esc(x)+'</li>').join('');$('[data-care-verifier]').innerHTML=r.verifierMesh.map(x=>'<li>'+esc(x)+'</li>').join('');$('[data-care-verdict]').textContent=r.governedDecisionState.verdict;$('[data-care-receipt]').textContent=JSON.stringify(r,null,2);}
  function run(text){const ta=$('[data-care-objective]')||$('[data-home-command]');const r=build(text||ta?.value||'');render(r);return r}
  function addMsg(role,html){const log=$('[data-care-chat-log]');if(!log)return;const div=document.createElement('div');div.className='care-msg '+(role==='user'?'user':'bot');div.innerHTML=html;log.appendChild(div);log.scrollTop=log.scrollHeight;}
  function answer(q){const text=String(q||'').trim();if(!text)return;addMsg('user','<b>You</b><p>'+esc(text)+'</p>');const r=build(text);const auto=/\b(open|go to|take me|show me|route me|send me)\b/i.test(text);addMsg('bot','<b>GoalOS</b><p>'+esc(r.recommendedRoute.why)+'</p><div class="care-msg-actions"><a class="care-btn primary" href="'+esc(r.recommendedRoute.href)+'">Open '+esc(r.recommendedRoute.title)+' →</a><button class="care-btn" type="button" data-care-use-answer>Use as mission</button></div>');render(r);if(auto){setTimeout(()=>{window.location.href=r.recommendedRoute.href},900)}}
  function copy(){const r=last||run();const txt='GoalOS Care Command v66\nObjective: '+r.objective+'\nRecommended route: '+r.recommendedRoute.title+' — '+r.recommendedRoute.href+'\nWhy: '+r.recommendedRoute.why+'\nNext: open the route, review the proof path, keep human authority.\nBoundary: local public-safe guidance only; no account, no wallet, no network request from console, no user data retained, no production authority.';if(navigator.clipboard&&navigator.clipboard.writeText)navigator.clipboard.writeText(txt).catch(()=>{});}
  function download(){const r=last||run();const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(r,null,2)],{type:'application/json'}));a.download='goalos-care-command-receipt-v66.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),900)}
  function init(){const ta=$('[data-care-objective]');$$('[data-care-example]').forEach(b=>b.addEventListener('click',()=>{if(ta){ta.value=b.getAttribute('data-care-example')||'';ta.focus();}}));$('[data-care-run]')?.addEventListener('click',()=>run());$('[data-care-clear]')?.addEventListener('click',()=>{if(ta)ta.value='';run('')});$('[data-care-copy]')?.addEventListener('click',copy);$('[data-care-download]')?.addEventListener('click',download);$('[data-care-ask]')?.addEventListener('click',()=>{const input=$('[data-care-question]');answer(input?.value||'');if(input)input.value=''});$('[data-care-question]')?.addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();$('[data-care-ask]')?.click();}});$$('[data-care-question-example]').forEach(b=>b.addEventListener('click',()=>answer(b.getAttribute('data-care-question-example')||'')));document.addEventListener('click',e=>{if(e.target.matches('[data-care-use-answer]')){const r=last;if(r&&ta){ta.value=r.objective;render(r)}}});run(ta?.value||'');}
  window.GOALOS_CARE_COMMAND_V66={build,run,answer,routes:ROUTES};if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);else init();
})();
